import{_ as a,c as i,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"外掛介紹: 功能與風險 | Antigravity Auth","description":"學習 Antigravity Auth 外掛的核心價值和風險提示。透過 Google OAuth 存取 Claude 和 Gemini 3 模型，支援多帳戶負載平衡。","frontmatter":{"title":"外掛介紹: 功能與風險 | Antigravity Auth","sidebarTitle":"這個外掛適合你嗎","subtitle":"了解 Antigravity Auth 外掛的核心價值","description":"學習 Antigravity Auth 外掛的核心價值和風險提示。透過 Google OAuth 存取 Claude 和 Gemini 3 模型，支援多帳戶負載平衡。","tags":["入門","外掛介紹","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"zh-tw/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"zh-tw/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),e={name:"zh-tw/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function r(n,t,s,h,d,u){return o(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="了解-antigravity-auth-外掛的核心價值" tabindex="-1">了解 Antigravity Auth 外掛的核心價值 <a class="header-anchor" href="#了解-antigravity-auth-外掛的核心價值" aria-label="Permalink to &quot;了解 Antigravity Auth 外掛的核心價值&quot;">​</a></h1><p><strong>Antigravity Auth</strong> 是一個 OpenCode 外掛，透過 Google OAuth 認證存取 Antigravity API。它讓你用熟悉的 Google 帳號就能呼叫 Claude Opus 4.5、Sonnet 4.5 和 Gemini 3 Pro/Flash 等進階模型，無需管理 API 金鑰。外掛還提供多帳戶負載平衡、雙配額池和自動對話恢復等功能，適合需要進階模型和自動管理的用戶。</p><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>判斷這個外掛是否適合你的使用情境</li><li>了解外掛支援哪些 AI 模型和核心功能</li><li>明確使用此外掛的風險和注意事項</li><li>決定是否繼續安裝和設定</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>想要使用最先進的 AI 模型（如 Claude Opus 4.5、Gemini 3 Pro），但官方存取受限。尋找可靠的方式取得這些模型，同時希望：</p><ul><li>不需要手動管理多個 API 金鑰</li><li>遇到速率限制時能自動切換帳戶</li><li>對話中斷後能自動恢復，不遺失上下文</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>Antigravity Auth</strong> 是一個 OpenCode 外掛，透過 <strong>Google OAuth 認證</strong> 存取 Google Antigravity API，讓你用自己熟悉的 Google 帳號就能呼叫進階 AI 模型。</p><p>它不是代理所有請求，而是<strong>攔截並轉換</strong>你的模型呼叫請求，將其轉發到 Antigravity API，再把回應轉換回 OpenCode 可以識別的格式。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h2><h3 id="支援的模型" tabindex="-1">支援的模型 <a class="header-anchor" href="#支援的模型" aria-label="Permalink to &quot;支援的模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型系列</th><th>可用模型</th><th>特點</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5、Sonnet 4.5</td><td>支援擴展思考模式</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro、Flash</td><td>Google Search 整合、擴展思考</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">思考模式（Thinking）</p><p>Thinking 模型會在生成回答前先進行「深度思考」，展示推理過程。你可以設定思考預算，平衡品質和回應速度。</p></div><h3 id="多帳戶負載平衡" tabindex="-1">多帳戶負載平衡 <a class="header-anchor" href="#多帳戶負載平衡" aria-label="Permalink to &quot;多帳戶負載平衡&quot;">​</a></h3><ul><li><strong>最多支援 10 個 Google 帳戶</strong></li><li>遇到速率限制（429 錯誤）時自動切換到下一個帳戶</li><li>三種帳戶選擇策略：sticky（固定）、round-robin（輪換）、hybrid（智慧混合）</li></ul><h3 id="雙配額系統" tabindex="-1">雙配額系統 <a class="header-anchor" href="#雙配額系統" aria-label="Permalink to &quot;雙配額系統&quot;">​</a></h3><p>外掛同時存取<strong>兩個獨立的配額池</strong>：</p><ol><li><strong>Antigravity 配額</strong>：來自 Google Antigravity API</li><li><strong>Gemini CLI 配額</strong>：來自 Google Gemini CLI</li></ol><p>當一個池限速時，外掛會自動嘗試另一個池，最大化配額利用率。</p><h3 id="自動對話恢復" tabindex="-1">自動對話恢復 <a class="header-anchor" href="#自動對話恢復" aria-label="Permalink to &quot;自動對話恢復&quot;">​</a></h3><ul><li>檢測工具呼叫失敗（如按 ESC 中斷）</li><li>自動注入 synthetic tool_result，避免對話崩潰</li><li>支援自動發送 &quot;continue&quot; 繼續對話</li></ul><h3 id="google-search-整合" tabindex="-1">Google Search 整合 <a class="header-anchor" href="#google-search-整合" aria-label="Permalink to &quot;Google Search 整合&quot;">​</a></h3><p>為 Gemini 模型啟用網頁搜尋，提升事實準確性：</p><ul><li><strong>Auto 模式</strong>：模型根據需要決定是否搜尋</li><li><strong>Always-on 模式</strong>：每次都搜尋</li></ul><h2 id="什麼時候用這個外掛" tabindex="-1">什麼時候用這個外掛 <a class="header-anchor" href="#什麼時候用這個外掛" aria-label="Permalink to &quot;什麼時候用這個外掛&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">適合以下情境</p><ul><li>你有多個 Google 帳號，希望提高總體配額</li><li>需要使用 Claude 或 Gemini 3 的 Thinking 模型</li><li>想要為 Gemini 模型啟用 Google Search</li><li>不想手動管理 API 金鑰，更習慣 OAuth 認證</li><li>經常遇到速率限制，希望自動切換帳戶</li></ul></div><div class="warning custom-block"><p class="custom-block-title">不適合以下情境</p><ul><li>你需要使用 Google 官方未公開的模型</li><li>你對 Google ToS 風險非常敏感（見下方風險提示）</li><li>你只需要基礎的 Gemini 1.5 或 Claude 3 模型（官方介面更穩定）</li><li>你在 WSL、Docker 等環境中開啟瀏覽器困難</li></ul></div><h2 id="⚠️-重要風險提示" tabindex="-1">⚠️ 重要風險提示 <a class="header-anchor" href="#⚠️-重要風險提示" aria-label="Permalink to &quot;⚠️ 重要風險提示&quot;">​</a></h2><p>使用此外掛<strong>可能違反 Google 的服務條款</strong>。少量用戶報告他們的 Google 帳號被<strong>封禁</strong>或<strong>影子封禁</strong>（限制存取但不明確通知）。</p><h3 id="高風險情境" tabindex="-1">高風險情境 <a class="header-anchor" href="#高風險情境" aria-label="Permalink to &quot;高風險情境&quot;">​</a></h3><ul><li>🚨 <strong>全新的 Google 帳號</strong>：被封禁機率極高</li><li>🚨 <strong>新開通 Pro/Ultra 訂閱的帳號</strong>：容易被標記並封禁</li></ul><h3 id="使用前請確認" tabindex="-1">使用前請確認 <a class="header-anchor" href="#使用前請確認" aria-label="Permalink to &quot;使用前請確認&quot;">​</a></h3><ul><li>這是一個<strong>非官方工具</strong>，Google 未認可</li><li>你的帳號可能被暫停或永久封禁</li><li>你承擔使用此外掛的所有風險</li></ul><h3 id="建議" tabindex="-1">建議 <a class="header-anchor" href="#建議" aria-label="Permalink to &quot;建議&quot;">​</a></h3><ul><li>使用<strong>成熟的 Google 帳號</strong>，而非為此外掛建立新帳號</li><li>避免使用與關鍵服務繫結的重要帳號</li><li>如果帳號被封禁，無法透過此外掛申訴</li></ul><div class="danger custom-block"><p class="custom-block-title">帳號安全</p><p>所有 OAuth 令牌都儲存在本地 <code>~/.config/opencode/antigravity-accounts.json</code>，不會上傳到任何伺服器。但請確保你的電腦安全，防止令牌洩漏。</p></div><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>Antigravity Auth 是一個強大的 OpenCode 外掛，讓你透過 Google OAuth 存取 Claude 和 Gemini 3 進階模型。它提供多帳戶負載平衡、雙配額池、自動對話恢復等功能，適合需要進階模型和自動管理的用戶。</p><p>但請務必注意：<strong>使用此外掛有封號風險</strong>。請使用非關鍵的 Google 帳號，並了解相關風險後再繼續安裝。</p><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../quick-install/">快速安裝</a></strong>。</p><p>你會學到：</p><ul><li>5 分鐘完成外掛安裝</li><li>新增第一個 Google 帳戶</li><li>驗證安裝成功</li></ul></blockquote>',42)])])}const p=a(e,[["render",r]]);export{c as __pageData,p as default};
